import numpy as np

def calculate_eigenvalues(matrix: list[list[float|int]]) -> list[float]:
    np_matrix = np.array(matrix, dtype=float)
    eigenvalues, _ = np.linalg.eig(np_matrix)
    return sorted(eigenvalues.real.tolist(), reverse=True)

