import torch

def calculate_eigenvalues(matrix: list[list[float|int]]) -> list[float]:
    tensor = torch.tensor(matrix, dtype=torch.float64)
    eigenvalues = torch.linalg.eigvals(tensor)
    real_eigenvalues = eigenvalues.real.tolist()
    return sorted(real_eigenvalues, reverse=True)
